            </div>
          </div>

          {/* Detailed View */}
          <div className="lg:col-span-8 xl:col-span-9">
            {activeStudy && (
              <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-blue-900/30 shadow-2xl overflow-hidden flex flex-col h-full">
                <div className="bg-slate-50 dark:bg-blue-900/30 px-6 py-4 border-b border-slate-200 dark:border-blue-900/30 flex flex-col xl:flex-row xl:items-center xl:justify-between gap-3">
                    <div>
                        <h3 className="text-lg font-black text-slate-900 dark:text-white mb-0.5 tracking-tight">{activeStudy.title}</h3>
