              <div key={index} className="bg-slate-50 dark:bg-slate-900/80 p-6 rounded-3xl shadow-sm border border-slate-200 dark:border-slate-800 hover:border-blue-500 transition-all group hover:-translate-y-2 hover:shadow-2xl">
                <div className="w-16 h-16 mx-auto mb-6 bg-white dark:bg-midnight rounded-2xl p-3 flex items-center justify-center group-hover:scale-110 transition-transform shadow-inner">
                  <img 
                    src={cert.logoUrl} 
                    alt={cert.issuer}
                    className="w-full h-full object-contain"
                  />
                </div>
                <h4 className="font-display font-extrabold text-slate-900 dark:text-white text-[14px] mb-1.5 leading-tight text-center tracking-tight">{cert.name}</h4>
                <p className="text-[9px] text-blue-600 dark:text-blue-400 font-black mb-3 text-center tracking-widest uppercase">{cert.issuer}</p>
                <p className="text-[11px] text-slate-500 dark:text-slate-400 leading-relaxed text-center font-medium">
                  {cert.description}
                </p>
              </div>
            ))}
          </div>
        </div>

        {/* Skills Categories */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-20">
          {SKILLS.map((category) => (
            <div key={category.title} className="bg-white dark:bg-slate-900/90 p-8 rounded-[2.5rem] shadow-sm border border-slate-100 dark:border-slate-800 relative overflow-hidden group hover:shadow-2xl transition-all duration-500">
              <div className="inline-flex items-center justify-center h-12 w-12 rounded-2xl bg-slate-50 dark:bg-midnight text-blue-600 dark:text-blue-400 mb-6 border border-slate-200 dark:border-slate-800 group-hover:bg-blue-600 group-hover:text-white transition-all">
                {icons[category.icon]}
              </div>
              <h3 className="font-display text-lg font-black text-slate-900 dark:text-white mb-6 tracking-tight">{category.title}</h3>
              <ul className="space-y-3.5">
                {category.skills.map((skill) => (
                  <li key={skill} className="flex items-center text-slate-600 dark:text-slate-400 font-bold text-[11px] uppercase tracking-wider">
                    <span className="w-1.5 h-1.5 bg-blue-500 rounded-full mr-4 flex-shrink-0 shadow-[0_0_8px_rgba(59,130,246,0.6)]"></span>
                    {skill}
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>

        {/* Tools Grid */}
        <div className="bg-slate-950 dark:bg-black rounded-[3rem] p-12 relative overflow-hidden transition-all duration-500 shadow-2xl border border-white/5 ring-1 ring-white/10">
            <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_50%_0%,rgba(59,130,246,0.1),transparent_50%)]"></div>
            <p className="font-display text-center text-slate-500 uppercase tracking-[0.45em] text-[10px] mb-12 font-black relative z-10">Enterprise Stack Proficiency</p>
            <div className="flex flex-wrap justify-center gap-12 md:gap-20 relative z-10">
                {TOOLS_LOGOS.map((tool, idx) => (
                    <div 
                      key={tool.name} 
                      className="group flex flex-col items-center gap-4"
                    >
                        <div className="h-10 w-10 md:h-12 md:w-12 transition-all duration-500 group-hover:-translate-y-2 group-hover:scale-110 flex items-center justify-center">
                          <img 
                            src={tool.logoUrl} 
                            alt={tool.name}
                            className="w-full h-full object-contain filter grayscale invert brightness-75 group-hover:grayscale-0 group-hover:invert-0 group-hover:brightness-100 transition-all duration-500"
                          />
                        </div>
                        <span className="text-[9px] font-black uppercase tracking-[0.35em] text-slate-600 group-hover:text-blue-400 transition-colors duration-300">{tool.name}</span>
                    </div>
                ))}
            </div>
        </div>
      </div>
    </section>
  );
};

export default Skills;

import React, { useState, useEffect } from 'react';
import { Menu, X, Terminal, Moon, Sun, FileDown } from 'lucide-react';

const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isDark, setIsDark] = useState(false);

  const navLinks = [
    { name: 'About', id: 'about' },
    { name: 'Methodology', id: 'methodology' },
    { name: 'Case Studies', id: 'work' },
    { name: 'Projects', id: 'projects' },
    { name: 'Skills', id: 'skills' },
    { name: 'Contact', id: 'contact' },
  ];

  useEffect(() => {
    // Check initial preference
    if (localStorage.theme === 'dark' || (!('theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      document.documentElement.classList.add('dark');
      setIsDark(true);
    } else {
      document.documentElement.classList.remove('dark');
      setIsDark(false);
    }
  }, []);

  const toggleDarkMode = () => {
    if (isDark) {
      document.documentElement.classList.remove('dark');
      localStorage.theme = 'light';
      setIsDark(false);
    } else {
      document.documentElement.classList.add('dark');
      localStorage.theme = 'dark';
      setIsDark(true);
    }
  };

  const handleScroll = (id: string) => {
    const element = document.getElementById(id);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth' });
      setIsOpen(false);
    }
  };

  return (
    <nav className="sticky top-0 z-50 bg-white/95 dark:bg-midnight/95 backdrop-blur-xl border-b border-slate-200 dark:border-slate-800 transition-colors duration-300">
      <div className="max-w-6xl mx-auto px-6 sm:px-10">
        <div className="flex justify-between h-20">
          <div className="flex items-center">
            <button 
              className="flex-shrink-0 flex items-center gap-3 cursor-pointer focus:outline-none" 
              onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
            >
              <div className="bg-blue-600 p-2 rounded-xl shadow-lg shadow-blue-600/20">
                <Terminal className="h-5 w-5 text-white" />
              </div>
              <span className="font-display font-black text-xl tracking-tighter text-slate-900 dark:text-white">Sharun<span className="text-blue-600">Suvarna</span></span>
            </button>
          </div>

          <div className="hidden md:flex items-center space-x-6">
            <div className="flex items-center space-x-6 mr-4 border-r border-slate-200 dark:border-slate-800 pr-6">
              {navLinks.map((link) => (
                <button
                  key={link.name}
                  onClick={() => handleScroll(link.id)}
                  className="text-[10px] font-black text-slate-500 dark:text-slate-400 hover:text-blue-600 dark:hover:text-blue-400 transition-colors focus:outline-none cursor-pointer uppercase tracking-[0.2em]"
                >
                  {link.name}
                </button>
              ))}
            </div>

            <div className="flex items-center gap-4">
              {/* Resume Download Button Desktop */}
              <a
                href="/resume.pdf"
                download="Sharun_Suvarna_Resume.pdf"
                className="inline-flex items-center gap-2 px-5 py-2.5 bg-gradient-to-r from-blue-600 to-indigo-600 hover:to-blue-500 text-white rounded-xl text-[10px] font-black uppercase tracking-widest transition-all transform hover:-translate-y-0.5 active:scale-95 shadow-lg shadow-blue-600/20"
              >
                <FileDown className="h-3.5 w-3.5" />
                Resume
              </a>

              {/* Dark Mode Toggle Desktop */}
              <button
                onClick={toggleDarkMode}
                className="p-2.5 rounded-xl text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors focus:outline-none border border-slate-200 dark:border-slate-800"
                aria-label="Toggle Dark Mode"
              >
                {isDark ? <Sun className="h-4 w-4" /> : <Moon className="h-4 w-4" />}
              </button>
            </div>
          </div>

          <div className="flex items-center gap-4 md:hidden">
            <button
              onClick={toggleDarkMode}
              className="p-2 rounded-xl text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors focus:outline-none"
            >
              {isDark ? <Sun className="h-5 w-5" /> : <Moon className="h-5 w-5" />}
            </button>

            <button
              onClick={() => setIsOpen(!isOpen)}
              className="inline-flex items-center justify-center p-2 rounded-xl text-slate-400 hover:text-slate-500 dark:hover:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 focus:outline-none"
            >
              {isOpen ? <X className="h-6 w-6" /> : <Menu className="h-6 w-6" />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile menu */}
      {isOpen && (
        <div className="md:hidden bg-white dark:bg-midnight border-b border-slate-200 dark:border-slate-800 animate-fade-in-up">
          <div className="px-8 pt-4 pb-8 space-y-2">
            {navLinks.map((link) => (
              <button
                key={link.name}
                onClick={() => handleScroll(link.id)}
                className="block w-full text-left py-4 text-[11px] font-black text-slate-600 dark:text-slate-300 hover:text-blue-600 dark:hover:text-blue-400 focus:outline-none uppercase tracking-[0.2em]"
              >
                {link.name}
              </button>
            ))}
            <div className="pt-4 mt-4 border-t border-slate-100 dark:border-slate-800">
               <a
                href="/resume.pdf"
                download="Sharun_Suvarna_Resume.pdf"
                className="flex items-center justify-center gap-3 w-full py-4 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-2xl text-[11px] font-black uppercase tracking-widest shadow-xl"
              >
                <FileDown className="h-4 w-4" />
                Download Resume PDF
              </a>
            </div>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
